                    margin: 10px 0;
                    position: relative;
                    padding-right: 15px !important;
                    text-align: center !important;

                    &:after {
                        font-family: 'verizon-icons' !important;
                        content: "\e9f3";
                        transform: rotate(90deg);
                        position: absolute;
                        /* display: block;*/
                        top: 35%;
                        bottom: 30%;
                        right: 0;
                        font-size: 14px;
                        background: #fff;
                        width: 20px;
                        height: 20px;
                        border-radius: 15px;
                    }

                    @media screen and (min-width: 320px) {
                        &:after {
                            left: 82% !important;
                        }
                    }

                    @media screen and (min-width: 768px) {
                        &:after {
                            left: 82% !important;
                        }
                    }

                    @media screen and (min-width: 991px) {
                        &:after {
                            left: 75% !important;
                        }
                    }
                }
            }

            .Accordion-detail {
                width: 100%;
                display: none;
                padding-bottom: 0px;
                opacity: 1 !important;
                padding-bottom: 10px;
                border-bottom: 0 !important;

            }

            &:not(.is-expanded) {
                .Accordion-button {
                    background-color: #fff;

                    &:after {
                        transition: transform .5s;
                    }
                }
            }

            &.is-expanded {
                .Accordion-button {
                    margin-bottom: -1px !important;

                    &:after {
                        transition: transform .5s;
                        transform: rotate(-90deg);
                    }
                }

                .Accordion-detail {
                    display: block;
                }
            }

        }
    }
}

