  <script>window.addEventListener('load', () => {
let accordianButtons = document.querySelectorAll(
  "#faq .Accordion-button, #save-on-plans .Accordion-button"
);

accordianButtons.forEach(function (button) {
  button.addEventListener("click", function () {
    let accordian = this.parentElement.parentElement;
    accordian.classList.toggle("is-expanded");
    if (accordian.getAttribute("aria-expanded") == "false") {
      accordian.setAttribute("aria-expanded", true);
      this.setAttribute("aria-expanded", true);
    } else {
      accordian.setAttribute("aria-expanded", false);
      this.setAttribute("aria-expanded", false);
    }
  });
});

const mainContent = document.getElementById("primary_content");
const secondaryContent = document.getElementById("secondary_content");
const toggleSwitch = document.querySelector('#custom-form-switch .toggleSwitch');
const formSwitch = document.querySelector('#custom-form-switch');

const updateContentVisibility = (isChecked) => {
  mainContent.style.display = isChecked ? "block" : "none";
  secondaryContent.style.display = isChecked ? "none" : "block";
};

const handleToggleSwitchChange = (event) => {
  updateContentVisibility(event.target.checked);
};

const handleKeyUp = (event) => {
  const { target, key } = event;
  const validKeys = ['enter'];

  if (!validKeys.includes(key.toLowerCase()) || !target.classList.contains('toggleSwitch')) return;

  target.checked = !target.checked;
  updateContentVisibility(target.checked);
};

formSwitch.addEventListener('keyup', handleKeyUp);
toggleSwitch.addEventListener('change', handleToggleSwitchChange);

});

</script>
